'use client';

import { useState } from 'react';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import { Button } from '@/components/ui/button';
import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Logo } from '@/components/logo';
import { AlertCircle, Loader2, ShieldCheck } from 'lucide-react';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { cn } from '@/lib/utils';

import { TechAuthBackground } from '@/components/ui-patterns/tech-auth-bg';
import { motion, AnimatePresence } from 'framer-motion';

export default function LoginPage() {
  const router = useRouter();
  const searchParams = useSearchParams();
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isLoading, setIsLoading] = useState(false);

  const from = searchParams.get('from') || '/portal';
  const verified = searchParams.get('verified') === 'true';

  const isAdminLogin = from.startsWith('/admin');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    setIsLoading(true);

    try {
      const res = await fetch('/api/auth/login', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ email, password }),
      });

      const data = await res.json();

      if (!res.ok) {
        throw new Error(data.error || 'Something went wrong');
      }

      router.push(from);
      router.refresh();
    } catch (err: any) {
      setError(err.message);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="relative min-h-screen flex items-center justify-center px-4 py-12 overflow-hidden">
      <TechAuthBackground />

      <motion.div
        initial={{ opacity: 0, y: 20, scale: 0.95 }}
        animate={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ duration: 0.5, ease: "easeOut" }}
        className="w-full max-w-md z-10"
      >
        <Card className={cn(
          "backdrop-blur-xl bg-white/90 dark:bg-slate-900/90 shadow-2xl transition-all duration-500 overflow-hidden",
          isAdminLogin ? "border-brand ring-4 ring-brand/10" : "border-white/10"
        )}>
          {/* Top Scanning Line Animation */}
          <motion.div 
            animate={{ left: ['-100%', '100%'] }}
            transition={{ duration: 3, repeat: Infinity, ease: "linear" }}
            className="absolute top-0 h-[2px] w-full bg-gradient-to-r from-transparent via-brand to-transparent opacity-50"
          />

          <CardHeader className="text-center pb-2">
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              transition={{ delay: 0.3 }}
            >
              <Logo className="justify-center mb-6" />
            </motion.div>
            
            <div className="space-y-1">
              <CardTitle className="text-2xl font-black uppercase tracking-tight text-slate-900 dark:text-white">
                {isAdminLogin ? 'Admin Console' : 'Client Portal'}
              </CardTitle>
              <CardDescription className="font-semibold text-slate-500">
                {isAdminLogin 
                  ? 'Infrastructure Management Console' 
                  : 'Access your technology roadmap'}
              </CardDescription>
            </div>

            {isAdminLogin && (
              <motion.div 
                initial={{ opacity: 0, scale: 0.8 }}
                animate={{ opacity: 1, scale: 1 }}
                className="mt-4 flex items-center justify-center gap-2 px-4 py-1.5 rounded-full bg-brand/10 text-brand border border-brand/20 w-fit mx-auto"
              >
                <ShieldCheck className="h-3.5 w-3.5 animate-pulse" />
                <span className="text-[10px] font-black uppercase tracking-[0.2em]">Authorized Access Only</span>
              </motion.div>
            )}
          </CardHeader>

          <CardContent className="pt-6">
            <AnimatePresence mode="wait">
              {verified && (
                <motion.div initial={{ height: 0, opacity: 0 }} animate={{ height: 'auto', opacity: 1 }} exit={{ height: 0, opacity: 0 }}>
                  <Alert className="mb-6 bg-green-500/10 text-green-600 border-green-500/20">
                    <AlertDescription>Identity verified. Please sign in.</AlertDescription>
                  </Alert>
                </motion.div>
              )}
              
              {error && (
                <motion.div initial={{ x: -10, opacity: 0 }} animate={{ x: 0, opacity: 1 }}>
                  <Alert variant="destructive" className="mb-6 border-destructive/20 bg-destructive/5">
                    <AlertCircle className="h-4 w-4" />
                    <AlertDescription className="font-medium">{error}</AlertDescription>
                  </Alert>
                </motion.div>
              )}
            </AnimatePresence>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="space-y-2">
                <Label htmlFor="email" className="text-xs font-bold uppercase tracking-wider text-slate-500">Corporate Email</Label>
                <Input
                  id="email"
                  type="email"
                  placeholder="admin@cyrotics.in"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  required
                  disabled={isLoading}
                  className="h-12 bg-slate-50/50 dark:bg-slate-800/50 border-slate-200 focus:ring-brand"
                />
              </div>
              <div className="space-y-2">
                <div className="flex items-center justify-between">
                  <Label htmlFor="password" className="text-xs font-bold uppercase tracking-wider text-slate-500">Security Key</Label>
                  <Link
                    href="/forgot-password"
                    className="text-[10px] font-bold uppercase text-brand hover:underline"
                  >
                    Reset Password
                  </Link>
                </div>
                <Input 
                  id="password" 
                  type="password" 
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  required 
                  disabled={isLoading}
                  className="h-12 bg-slate-50/50 dark:bg-slate-800/50 border-slate-200 focus:ring-brand"
                />
              </div>
              <Button type="submit" className="w-full h-12 bg-brand hover:bg-brand/90 text-white font-bold text-sm shadow-lg shadow-brand/20 transition-all active:scale-[0.98]" disabled={isLoading}>
                {isLoading ? (
                  <>
                    <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                    Validating...
                  </>
                ) : (
                  isAdminLogin ? 'Unlock Console' : 'Sign In to Portal'
                )}
              </Button>
            </form>
            <div className="mt-8 pt-6 border-t border-slate-100 dark:border-slate-800 text-center text-xs text-muted-foreground">
              New to CYROTICS?{' '}
              <Link
                href="/register"
                className="font-black text-brand hover:underline uppercase tracking-tighter"
              >
                Request Access
              </Link>
            </div>
          </CardContent>
        </Card>
      </motion.div>
    </div>
  );
}

